import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(a, b):
        return np.linalg.norm(a - b)

    if len(unvisited_customers) == 0:
        return None  # Trigger for the truck to wait or return to depot

    weights = np.zeros(len(unvisited_customers))

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer)
        dist_customer_to_depot = distance(depot_pos, customer)

        # Calculate weighted score for proximity to depot and the current position
        proximity_weight = 1 / (1 + dist_to_customer)
        depot_proximity_bonus = 1 / (1 + dist_customer_to_depot)

        congestion_penalty = 0
        for other_truck in all_truck_pos:
            if np.array_equal(other_truck, cur_truck_pos):
                continue
            prox_to_customer_from_other = distance(other_truck, customer)
            if prox_to_customer_from_other < 2 * dist_to_customer:
                congestion_penalty += 0.5 * (2 - prox_to_customer_from_other / dist_to_customer)

        # Combining weights dynamically with emphasis on depot proximity
        weights[i] = proximity_weight + 0.5 * depot_proximity_bonus - congestion_penalty

    best_node = np.argmax(weights)

    return best_node
